import{_ as r,o as p,c as t,j as a,a as s,a1 as d}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"褪色者","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/6.一次性血统/褪色者.md","filePath":"4.资源分区/1.血统与训练/6.一次性血统/褪色者.md"}'),n={name:"4.资源分区/1.血统与训练/6.一次性血统/褪色者.md"};function o(l,e,_,i,c,b){return p(),t("div",null,[...e[0]||(e[0]=[a("h1",{id:"褪色者",tabindex:"-1"},[s("褪色者 "),a("a",{class:"header-anchor",href:"#褪色者","aria-label":'Permalink to "褪色者"'},"​")],-1),a("table",{class:"bannerparthead"},[a("tbody",null,[a("tr",{id:"hdr"},[a("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调019")])])],-1),d('<h1 id="褪色者-1" tabindex="-1">褪色者 <a class="header-anchor" href="#褪色者-1" aria-label="Permalink to &quot;褪色者&quot;">​</a></h1><p>一次性血统：褪色者<br> 介绍：褪色者是《艾尔登法环》世界观中，追随初始之王葛孚雷的战士的血裔，他们随着初王一起，被放逐出了交界地之外。<br> 恶兆妖鬼曾经称赞：“褪色者不愧是战士的后裔。”他们都拥有极高的战斗的禀赋，并且能够利用获取的卢恩来强化自身。能够快速地从一介小卒成长为能与神明角力的强者。</p><p>价格：C+1200<br> 特性：<br> 【出身】：褪色者具有不同的出身，并且因为出身的不同，所具有的初始的能力也不同。<br> 你从下述的出身当中选择一个，获得对应的效果。<br> “流浪骑士”：你的力量和耐力分别获得2点内在加值。如果你持有盾牌，那么你在专长：游刃有余的第二级“强化防御”中获得的格挡防御加值增加4点。</p><p>“剑士”：你的敏捷和感知分别获得2点内在加值。你在持有并且满足专长：无双剑士的发动要求时，额外在攻击上具有5点高速。并且你的移动速度提升10米。</p><p>“勇者”：你的力量获得4点内在加值。你在专长：饥渴大斧的第二级“上阵杀敌”中获得的攻击增益再额外追加两点附加成功。</p><p>“盗贼”：你的敏捷获得4点内在加值。你在专长：诡诈奸兵的第二级“龙吻”中获得的高速翻倍。并且现在你持用满足诡诈奸兵要求的武器攻击时，如果破除完对应防御高速还有剩余的话，可以将至多10点溢出的高速转化为dp。</p><p>“观星者”：你的智力获得4点内在加值。你在进行核心派系的魔法的施法检定时，你的法术强度提升3点。你任选一个心智类能量池扩大6点。</p><p>“预言家”：你的决心获得4点内在加值。你获得基于听觉的强感知方式。</p><p>“武士”：你的力量和沉着各获得2点内在加值。你在专长：居合道的第二级中获得的【先制】提升到C级，并且在对先攻低于你的对手进行攻击时，你还额外会提升手中满足居合道使用条件的武器的3点武器伤害。</p><p>“囚犯”：你的敏捷和智力各获得2点内在加值。你在隐秘技能和学识技能鉴定上获得3dp加值。</p><p>“密使”：你的力量和决心各获得2点内在加值。你在武技技能和学识技能鉴定上获得3dp加值。</p><p>“无用之人”：你不获得任何内在加值。你在基因锁鉴定上额外获得2点加值，无法与其他类似的加值叠加。<br> 你在机运检定上获得2点加值，无法与其他类似的加值叠加。</p><p>因为属性均已通过各种出身给出，这个一次性血统并不会让你额外获得自由分配的内在属性。<br> 【卢恩汲取】：褪色者能够从卢恩中获取力量，然而，因为在主神空间，既没有指头女巫，也没有梅琳娜，只能由主神代理指头女巫的业务，帮助你把卢恩转化成力量。<br> 一场影片一次，当你赢得一次平级战斗时，你可以获得1点卢恩。<br> 一场影片一次，当你赢得一次高一级战斗时，你可以获得2点卢恩。<br> 在影片结束后，你回到主神空间，可以将卢恩一比一兑换成属性，同样无法超过属性上限。</p><p>【战士禀赋】：褪色者拥有战士的血统，对于战灰的使用得心应手，因而你现在每轮额外获得2点AP，用于转化施展战灰所附属的战技。此外，若施展的是攻击类战技，则你在攻击检定中获得6DP内在加值。</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',16)])])}const f=r(n,[["render",o]]);export{m as __pageData,f as default};
